'use client';

import { useState, useEffect, useCallback } from 'react';
import { useRecorder } from '@/lib/audio/hooks';
import { Spectrogram, TimbralManifold } from '@/lib/audio/visualizations';
import { CALLS, generateMockFrames } from '@/lib/calls';
import type { AudioFeatureFrame } from '@/lib/audio/scorer';

const COLORS = { bg: '#09090b', surface: '#111114', surfaceAlt: '#18181b', border: '#27272a', text: '#fafafa', textMuted: '#52525b', accent: '#22c55e', reference: '#3b82f6', danger: '#ef4444' };

export default function TrainPage() {
  const [callId, setCallId] = useState('yelp');
  const [refFrames, setRefFrames] = useState([]);
  const [playbackFrame, setPlaybackFrame] = useState(0);
  const [isPlayingRef, setIsPlayingRef] = useState(false);
  const [viewMode, setViewMode] = useState<'reference' | 'user'>('reference');

  const { state, frames: userFrames, result, startRecording, stopRecording, reset } = useRecorder(refFrames, { maxDuration: 10, minDuration: 0.5 });

  useEffect(() => { setRefFrames(generateMockFrames(callId)); setPlaybackFrame(0); setViewMode('reference'); reset(); }, [callId, reset]);

  useEffect(() => {
    if (!isPlayingRef) return;
    setPlaybackFrame(0);
    const interval = setInterval(() => setPlaybackFrame(f => { if (f >= refFrames.length - 1) { setIsPlayingRef(false); return 0; } return f + 1; }), 1000 / 30);
    return () => clearInterval(interval);
  }, [isPlayingRef, refFrames.length]);

  useEffect(() => {
    if (state !== 'complete' || userFrames.length === 0) return;
    setViewMode('user'); setPlaybackFrame(0);
    let frame = 0;
    const interval = setInterval(() => { setPlaybackFrame(frame); frame++; if (frame >= userFrames.length) clearInterval(interval); }, 1000 / 30);
    return () => clearInterval(interval);
  }, [state, userFrames.length]);

  const handleRecord = useCallback(() => { if (state === 'recording') stopRecording(); else { reset(); startRecording(); } }, [state, startRecording, stopRecording, reset]);
  const handlePlayRef = useCallback(() => { if (state === 'recording') return; setViewMode('reference'); setIsPlayingRef(p => !p); }, [state]);

  const displayFrames = viewMode === 'user' && userFrames.length > 0 ? userFrames : refFrames;
  const displayFrame = Math.min(playbackFrame, displayFrames.length - 1);

  return (






SHOCKTALK

Train your turkey calls




          {CALLS.map(call => (
             setCallId(call.id)} style={{ padding: '10px 16px', borderRadius: 6, border: `1px solid ${callId === call.id ? COLORS.accent : COLORS.border}`, background: callId === call.id ? 'rgba(34,197,94,0.1)' : COLORS.surface, color: callId === call.id ? COLORS.accent : COLORS.textMuted, fontSize: 13, fontWeight: 500, cursor: 'pointer' }}>{call.name}
          ))}


        {result && (



= 80 ? COLORS.accent : result.score >= 50 ? '#eab308' : COLORS.danger, textShadow: `0 0 30px ${result.score >= 80 ? COLORS.accent : result.score >= 50 ? '#eab308' : COLORS.danger}40` }}>{result.score}

{result.feedback}


              Pitch: {result.breakdown.pitch}Rhythm: {result.breakdown.rhythm}Duration: {result.breakdown.duration}


        )}






        {state === 'complete' && (


            {(['reference', 'user'] as const).map(m => (
               { setViewMode(m); setPlaybackFrame(0); const f = m === 'user' ? userFrames : refFrames; let i = 0; const int = setInterval(() => { setPlaybackFrame(i); i++; if (i >= f.length) clearInterval(int); }, 1000 / 30); }} style={{ padding: '8px 16px', borderRadius: 6, border: 'none', background: viewMode === m ? COLORS.surfaceAlt : 'transparent', color: viewMode === m ? COLORS.text : COLORS.textMuted, fontSize: 12, fontWeight: 500, cursor: 'pointer' }}>{m === 'reference' ? 'Reference' : 'Your Call'}
            ))}

        )}




            {state === 'recording' ? '■' : '●'}
            {state === 'recording' ? 'Stop' : state === 'processing' ? '...' : 'Record'}


            {isPlayingRef ? '■' : '▶'}{isPlayingRef ? 'Stop' : 'Play Reference'}





          {state === 'idle' && 'Listen to the reference, then record your attempt'}
          {state === 'recording' && 'Make your call — tap stop when done'}
          {state === 'processing' && 'Analyzing...'}
          {state === 'complete' && 'Compare your call to the reference'}



  );
}

import { useState, useRef, useCallback, useEffect } from 'react';
import { AudioFeatureFrame, ScoringResult, calculateSimilarityScore } from './scorer';

export type RecorderState = 'idle' | 'requesting' | 'recording' | 'processing' | 'complete' | 'error';

export function useRecorder(referenceFrames: AudioFeatureFrame[], options: { maxDuration?: number; minDuration?: number } = {}) {
  const { maxDuration = 15, minDuration = 0.5 } = options;

  const [state, setState] = useState('idle');
  const [frames, setFrames] = useState([]);
  const [currentFrame, setCurrentFrame] = useState(null);
  const [result, setResult] = useState(null);
  const [error, setError] = useState(null);

  const audioContextRef = useRef(null);
  const analyzerRef = useRef(null);
  const streamRef = useRef(null);
  const startTimeRef = useRef(0);
  const intervalRef = useRef(null);
  const timeoutRef = useRef(null);
  const collectedRef = useRef([]);
  const smoothRef = useRef({ centroid: 0, energy: 0, spread: 0 });

  const cleanup = useCallback(() => {
    if (intervalRef.current) clearInterval(intervalRef.current);
    if (timeoutRef.current) clearTimeout(timeoutRef.current);
    try { analyzerRef.current?.stop(); } catch {}
    streamRef.current?.getTracks().forEach(t => t.stop());
    if (audioContextRef.current?.state !== 'closed') audioContextRef.current?.close();
    intervalRef.current = timeoutRef.current = analyzerRef.current = streamRef.current = audioContextRef.current = null;
  }, []);

  useEffect(() => cleanup, [cleanup]);

  const startRecording = useCallback(async () => {
    setFrames([]); setCurrentFrame(null); setResult(null); setError(null);
    collectedRef.current = []; smoothRef.current = { centroid: 0, energy: 0, spread: 0 };
    setState('requesting');

    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: { echoCancellation: false, noiseSuppression: false, autoGainControl: false } });
      streamRef.current = stream;

      const ctx = new AudioContext({ sampleRate: 44100 });
      audioContextRef.current = ctx;
      if (ctx.state === 'suspended') await ctx.resume();

      const source = ctx.createMediaStreamSource(stream);
      const Meyda = (await import('meyda')).default;
      startTimeRef.current = performance.now();

      analyzerRef.current = Meyda.createMeydaAnalyzer({
        audioContext: ctx, source, bufferSize: 512,
        featureExtractors: ['spectralCentroid', 'rms', 'spectralSpread', 'spectralFlatness'],
        callback: (f: any) => {
          const time = (performance.now() - startTimeRef.current) / 1000;
          const s = smoothRef.current, alpha = 0.3;
          const centroid = s.centroid ? alpha * f.spectralCentroid + (1 - alpha) * s.centroid : f.spectralCentroid;
          const energy = s.energy ? alpha * f.rms + (1 - alpha) * s.energy : f.rms;
          const spread = s.spread ? alpha * f.spectralSpread + (1 - alpha) * s.spread : f.spectralSpread;
          s.centroid = centroid; s.energy = energy; s.spread = spread;

          const frame: AudioFeatureFrame = {
            time, spectralCentroid: (centroid || 0) * ctx.sampleRate / 2,
            rmsEnergy: Math.min(1, energy || 0), spectralSpread: (spread || 0) * ctx.sampleRate / 2, spectralFlatness: f.spectralFlatness || 0,
          };
          collectedRef.current.push(frame);
          setCurrentFrame(frame);
        },
      });

      analyzerRef.current.start();
      setState('recording');
      intervalRef.current = window.setInterval(() => setFrames([...collectedRef.current]), 100);
      timeoutRef.current = window.setTimeout(() => stopRecording(), maxDuration * 1000);
    } catch (err: any) {
      cleanup();
      setError(err.name === 'NotAllowedError' ? 'Microphone access denied' : 'Recording failed');
      setState('error');
    }
  }, [maxDuration, cleanup]);

  const stopRecording = useCallback(() => {
    if (state !== 'recording') return;
    const finalFrames = [...collectedRef.current];
    const duration = (performance.now() - startTimeRef.current) / 1000;
    cleanup();
    setState('processing');

    setTimeout(() => {
      if (duration < minDuration) { setError('Recording too short'); setState('error'); return; }
      try {
        const res = calculateSimilarityScore(referenceFrames, finalFrames);
        setFrames(finalFrames); setResult(res); setState('complete');
      } catch { setError('Analysis failed'); setState('error'); }
    }, 100);
  }, [state, referenceFrames, minDuration, cleanup]);

  const reset = useCallback(() => {
    cleanup(); setFrames([]); setCurrentFrame(null); setResult(null); setError(null); setState('idle');
  }, [cleanup]);

  return { state, frames, currentFrame, result, error, startRecording, stopRecording, reset };
}

export type AudioFeatureFrame = {
  time: number;
  spectralCentroid: number;
  rmsEnergy: number;
  spectralSpread: number;
  spectralFlatness: number;
};

export type ScoreBreakdown = {
  pitch: number;
  rhythm: number;
  duration: number;
  overall: number;
};

export type ScoringResult = {
  score: number;
  breakdown: ScoreBreakdown;
  feedback: string;
};

const WEIGHTS = { pitch: 0.6, rhythm: 0.3, duration: 0.1 };

function normalize(arr: number[]): number[] {
  if (arr.length === 0) return [];
  const min = Math.min(...arr);
  const max = Math.max(...arr);
  const range = max - min || 1;
  return arr.map(v => (v - min) / range);
}

function dtw(seq1: number[], seq2: number[]): number {
  const n = seq1.length;
  const m = seq2.length;
  if (n === 0 || m === 0) return Infinity;

  const window = Math.max(Math.floor(Math.max(n, m) * 0.2), 2);
  const dp: number[][] = Array(n + 1).fill(null).map(() => Array(m + 1).fill(Infinity));
  dp[0][0] = 0;

  for (let i = 1; i <= n; i++) {
    const jStart = Math.max(1, i - window);
    const jEnd = Math.min(m, i + window);
    for (let j = jStart; j <= jEnd; j++) {
      const cost = Math.abs(seq1[i - 1] - seq2[j - 1]);
      dp[i][j] = cost + Math.min(dp[i - 1][j], dp[i][j - 1], dp[i - 1][j - 1]);
    }
  }

  return dp[n][m] / Math.max(n, m);
}

function calculatePitchScore(ref: AudioFeatureFrame[], user: AudioFeatureFrame[]): number {
  const refCentroid = normalize(ref.map(f => f.spectralCentroid));
  const userCentroid = normalize(user.map(f => f.spectralCentroid));
  const distance = dtw(refCentroid, userCentroid);
  return Math.max(0, Math.min(100, 100 - distance * 200));
}

function calculateRhythmScore(ref: AudioFeatureFrame[], user: AudioFeatureFrame[]): number {
  const refEnergy = ref.map(f => f.rmsEnergy);
  const userEnergy = user.map(f => f.rmsEnergy);
  const distance = dtw(refEnergy, userEnergy);
  return Math.max(0, Math.min(100, 100 - distance * 150));
}

function calculateDurationScore(ref: AudioFeatureFrame[], user: AudioFeatureFrame[]): number {
  const ratio = Math.min(ref.length, user.length) / Math.max(ref.length, user.length);
  return Math.round(Math.pow(ratio, 0.5) * 100);
}

function generateFeedback(pitch: number, rhythm: number, duration: number): string {
  if (pitch >= 85 && rhythm >= 85 && duration >= 80) return 'Excellent call! Field ready.';
  if (pitch >= 75 && rhythm >= 75) return 'Good call. Minor refinements possible.';
  const weakest = Math.min(pitch, rhythm, duration);
  if (weakest === pitch) return pitch < 50 ? 'Focus on matching the pitch contour.' : 'Pitch is close. Match frequency peaks.';
  if (weakest === rhythm) return rhythm < 50 ? 'Work on your timing.' : 'Rhythm is close. Mind the pauses.';
  if (weakest === duration) return 'Adjust your call length to match reference.';
  return 'Keep practicing.';
}

export function calculateSimilarityScore(ref: AudioFeatureFrame[], user: AudioFeatureFrame[]): ScoringResult {
  if (ref.length < 5 || user.length < 5) {
    return { score: 0, breakdown: { pitch: 0, rhythm: 0, duration: 0, overall: 0 }, feedback: 'Recording too short.' };
  }

  const pitch = calculatePitchScore(ref, user);
  const rhythm = calculateRhythmScore(ref, user);
  const duration = calculateDurationScore(ref, user);
  const raw = pitch * WEIGHTS.pitch + rhythm * WEIGHTS.rhythm + duration * WEIGHTS.duration;
  const overall = Math.round(Math.pow(raw / 100, 0.85) * 100);

  return {
    score: overall,
    breakdown: { pitch: Math.round(pitch), rhythm: Math.round(rhythm), duration: Math.round(duration), overall },
    feedback: generateFeedback(pitch, rhythm, duration),
  };
}

import type { AudioFeatureFrame } from './audio/scorer';

export type CallType = { id: string; name: string; description: string; difficulty: 'easy' | 'medium' | 'hard'; category: 'hen' | 'gobbler' };

export const CALLS: CallType[] = [
  { id: 'yelp', name: 'Plain Yelp', description: 'Basic hen call', difficulty: 'easy', category: 'hen' },
  { id: 'cluck', name: 'Cluck', description: 'Short sharp notes', difficulty: 'easy', category: 'hen' },
  { id: 'gobble', name: 'Gobble', description: 'Rapid oscillation', difficulty: 'medium', category: 'gobbler' },
];

export function generateMockFrames(callId: string, duration = 2.5): AudioFeatureFrame[] {
  const fps = 30, frames: AudioFeatureFrame[] = [], numFrames = Math.floor(duration * fps);

  for (let i = 0; i < numFrames; i++) {
    const t = i / numFrames;
    let centroid: number, energy: number, spread: number;

    switch (callId) {
      case 'yelp': { const cycle = (t * 3.5) % 1, env = Math.pow(Math.sin(cycle * Math.PI), 1.5); centroid = 650 + env * 750; energy = env * 0.85 + 0.08; spread = 120 + env * 180; break; }
      case 'cluck': { const cycle = (t * 6) % 1, env = cycle < 0.15 ? Math.sin(cycle * Math.PI / 0.15) : 0; centroid = 450 + env * 250; energy = env * 0.95; spread = 80 + env * 120; break; }
      case 'gobble': { const wobble = Math.sin(t * 55) * 0.5 + 0.5, env = Math.sin(t * Math.PI) * 0.8 + 0.2; centroid = 520 + wobble * 380; energy = env * wobble * 0.75 + 0.15; spread = 160 + wobble * 140; break; }
      default: { centroid = 500; energy = 0.5; spread = 150; }
    }

    frames.push({ time: t * duration, spectralCentroid: centroid, rmsEnergy: energy, spectralSpread: spread, spectralFlatness: 0.3 });
  }
  return frames;
}
